import{_ as t,H as r,f as e,i as s}from"./chunks/framework.Cvt1eIE0.js";const a="/store-locator/images/dashboard-home.png",i="/store-locator/images/google-maps-settings.png",n="/store-locator/images/stores-index.png",l="/store-locator/images/add-store-form.png",g="/store-locator/images/pick-from-map.png",p="/store-locator/images/add-section.png",A=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"store-locator/guide/getting-started.md","filePath":"store-locator/guide/getting-started.md"}'),d={name:"store-locator/guide/getting-started.md"};function c(m,o,_,h,u,S){return r(),e("div",null,[...o[0]||(o[0]=[s('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><p>欢迎使用 <strong>Jika Store Locator</strong>！本指南将帮助您在几分钟内完成设置，并在您的 Shopify 店铺中上线门店定位器。</p><h2 id="_1-安装应用" tabindex="-1">1. 安装应用 <a class="header-anchor" href="#_1-安装应用" aria-label="Permalink to &quot;1. 安装应用&quot;">​</a></h2><p>从 Shopify 应用商店安装应用后，您将进入应用仪表盘（Home）。 <img src="'+a+'" alt="应用仪表盘"></p><h2 id="_2-配置-google-maps-api" tabindex="-1">2. 配置 Google Maps API <a class="header-anchor" href="#_2-配置-google-maps-api" aria-label="Permalink to &quot;2. 配置 Google Maps API&quot;">​</a></h2><p>门店定位器需要 Google Maps API 密钥来渲染地图和解析地址。</p><ol><li><p>点击Home页中的<strong>Check API key</strong>或进入应用设置中的 <strong>Integrations (集成)</strong> 标签页。 <img src="'+i+'" alt="Google Maps 配置"></p></li><li><p>输入您的 <strong>Google Maps API Key</strong>。</p><ul><li><em>注意：请确保已在 Google Cloud 控制台中启用了 Maps JavaScript API ,Places API和 Geocoding API。</em></li></ul></li><li><p>点击 <strong>Save (保存)</strong>。</p></li></ol><h2 id="_3-添加门店-add-store" tabindex="-1">3. 添加门店 (Add Store) <a class="header-anchor" href="#_3-添加门店-add-store" aria-label="Permalink to &quot;3. 添加门店 (Add Store)&quot;">​</a></h2><ol><li><p>导航到应用首页或菜单中的 <strong>Stores (门店)</strong> 部分并点击 <strong>Add Store (添加门店)</strong> 或 <strong>Add First Store</strong>。您也可以选择 <strong>Import CSV</strong> 批量导入。 <img src="'+n+'" alt="门店列表页面"></p></li><li><p>填写门店名称、电话、网站等并上传门店图片（可选）。 <img src="'+l+'" alt="添加门店表单"></p></li><li><p>或点击右上角<strong>pick from map</strong>使用在谷歌地图上找到您店铺的位置，自动带入相关信息。 <img src="'+g+'" alt="从地图选取位置"></p></li><li><p>将门店状态设为 <strong>Active (启用)</strong> 并点击 <strong>Save (保存)</strong>。</p></li></ol><h2 id="_4-在前台发布定位器" tabindex="-1">4. 在前台发布定位器 <a class="header-anchor" href="#_4-在前台发布定位器" aria-label="Permalink to &quot;4. 在前台发布定位器&quot;">​</a></h2><p>我们提供了 3 种灵活的发布模式（独立页面、主题区块、悬浮挂件）。</p><ol><li>回到首页，在 <strong>Quick Setup Roadmap</strong> 中找到第三步 <strong>Publish Store Locator</strong>，点击 <strong>Publish Options</strong>。</li><li>在 Publish 页面，您可以选择： <ul><li><strong>Mode 1: Managed Storefront Page</strong>（自动创建独立页面，支持 Classic 和 Stacked 布局）。</li><li><strong>Mode 2: Theme Section</strong>（在您现有的页面中插入地图区块，支持全量 9 种布局）。</li><li><strong>Mode 3: Floating Widget</strong>（全局悬浮地图按钮）。</li></ul></li><li>如果您选择 Mode 2 添加到现有页面，点击 <strong>Open Theme Editor</strong>，在左侧侧边栏点击 <strong>Add section</strong>，在 Apps 中选择 <strong>Jika Store Locator</strong> 即可。 <img src="'+p+'" alt="添加地图"></li><li>您可以前往首页点击 <strong>APPEARANCE SETTINGS</strong> 下的 <strong>Manage Appearance</strong> 来自由配置地图颜色、标记和卡片圆角等外观样式。</li><li>点击 <strong>Save (保存)</strong> 即可上线。</li></ol><p>现在，您的客户就可以在前端查找您的门店了！</p>',13)])])}const f=t(d,[["render",c]]);export{A as __pageData,f as default};
